-- Seed temples
INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Kedarnath Temple', 'kedarnath', 'Uttarakhand', 'Kedarnath', 'Shiva', 'North Indian Himalayan', 'One of the twelve Jyotirlingas of Shiva, located in the Garhwal Himalayas at 3,583 m elevation. The temple is built from massive stone slabs and is believed to be over 1,200 years old, attributed to the Pandavas.', 'Kedarnath is part of the Char Dham pilgrimage circuit. The temple is believed to have been built by the Pandavas to atone for their sins after the Kurukshetra war. Adi Shankaracharya is said to have attained Mahasamadhi here. The temple survived the 2013 Uttarakhand floods with minimal damage while everything around was destroyed.', 30.7352, 79.0669, 120, true, NOW(), NOW())
