VALUES ('Badrinath Temple', 'badrinath', 'Uttarakhand', 'Badrinath', 'Vishnu', 'North Indian Himalayan', 'A sacred Vaishnavite temple in the Garhwal Himalayas, part of the Char Dham circuit. The temple features a black stone idol of Lord Badrinarayan seated in a meditative pose.', 'Badrinath has been mentioned in the Puranas as a sacred site for millennia. The current temple was established by Adi Shankaracharya in the 8th century. It is one of the 108 Divya Desams dedicated to Vishnu. The temple remains open for six months each year due to extreme weather.', 30.7433, 79.4938, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Somnath Temple', 'somnath', 'Gujarat', 'Prabhas Patan', 'Shiva', 'Chalukya', 'The first of the twelve Jyotirlingas, Somnath is a temple rebuilt multiple times after successive invasions. The current structure in Chalukya style was completed in 1951.', 'Somnath is mentioned in the Rigveda and is believed to be the first Jyotirlinga. The temple was looted by Mahmud of Ghazni in 1025 CE. It was rebuilt by various Hindu kings and the Marathas before being reconstructed in its current form after independence. The temple faces the Arabian Sea and has no land between it and the South Pole.', 20.8883, 70.4014, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Dwarkadhish Temple', 'dwarkadhish', 'Gujarat', 'Dwarka', 'Krishna', 'Chalukya', 'Also known as Jagat Mandir, this five-storeyed temple is dedicated to Krishna as the King of Dwarka. It is part of the Char Dham circuit and one of the 108 Divya Desams.', 'The temple marks the site where Krishna is said to have established his kingdom after leaving Mathura. The current structure dates to the 16th century, though the site is far more ancient. The flag on the temple changes five times a day. Dwarka is also one of the seven Moksha-puris of Hinduism.', 22.2372, 68.9677, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Jagannath Temple', 'jagannath-puri', 'Odisha', 'Puri', 'Jagannath (Krishna)', 'Kalinga', 'A massive temple complex dedicated to Jagannath, a form of Krishna, along with Balabhadra and Subhadra. Famous for the annual Rath Yatra chariot festival.', 'The temple was built in the 12th century by King Anantavarman Chodaganga Deva. The wooden idols are replaced every 12-19 years in a secret Nabakalebara ceremony. The temple kitchen can feed 100,000 people daily. Non-Hindus are traditionally not allowed inside, but the temple can be viewed from the nearby Raghunandan Library.', 19.8047, 85.8186, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Ramanathaswamy Temple', 'rameswaram', 'Tamil Nadu', 'Rameswaram', 'Shiva', 'Dravidian', 'A sprawling temple complex on Rameswaram island, with the longest temple corridor in India (1,000 m). It is part of the Char Dham circuit and one of the twelve Jyotirlingas.', 'Rameswaram is believed to be the place where Ram built a bridge to Lanka. The temple''s 22 wells (theerthams) are considered sacred. The current structure was built over several centuries, with major contributions from the Sethupathy rulers. The temple has 1,200 granite pillars lining its corridors.', 9.2876, 79.3129, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Meenakshi Amman Temple', 'meenakshi', 'Tamil Nadu', 'Madurai', 'Parvati (Meenakshi)', 'Dravidian', 'A historic temple complex with 14 towering gopurams, the tallest being over 50 m high. The temple is the epicenter of Madurai city and a masterpiece of Dravidian architecture.', 'The temple has been mentioned in Tamil Sangam literature. The current structure was rebuilt by the Nayak rulers in the 16th-17th centuries. The Hall of Thousand Pillars (actually 985) is a marvel of engineering. The temple has over 33,000 sculptures depicting scenes from Hindu mythology.', 9.9195, 78.1197, 150, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Brihadeeswarar Temple', 'brihadeeswarar', 'Tamil Nadu', 'Thanjavur', 'Shiva', 'Dravidian (Chola)', 'A UNESCO World Heritage Site built by Raja Raja Chola I. The temple''s vimana (tower) rises 66 m, making it one of the tallest of its kind. The massive lingam is one of the largest in India.', 'Completed in 1010 CE, this temple is the crown jewel of Chola architecture. The capstone is a single granite block weighing 80 tons, raised using a 6 km long ramp. The temple frescoes depict Chola history. The shadows of the gopuram never fall on the ground at noon.', 10.7828, 79.1319, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Sri Venkateswara Temple', 'tirupati', 'Andhra Pradesh', 'Tirumala', 'Vishnu (Venkateswara)', 'Dravidian', 'The richest and most visited temple in India, situated on the seventh peak of the Tirumala hills. The temple receives over 40,000 visitors daily and up to 200,000 on special days.', 'The temple is mentioned in the Puranas and has been patronized by dynasties including the Pallavas, Cholas, and Vijayanagara Empire. The idol is believed to be self-manifested. The temple''s hundi (donation box) collects crores of rupees daily. The Laddu prasadam is GI-tagged.', 13.6833, 79.3500, 180, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Harmandir Sahib', 'golden-temple', 'Punjab', 'Amritsar', 'Sikhism (Guru Granth Sahib)', 'Sikh Architecture', 'The holiest Gurdwara of Sikhism, known as the Golden Temple for its gold-plated sanctum. The temple sits in the middle of the Amrit Sarovar (holy tank).', 'The foundation was laid by Guru Arjan Dev in 1588 and the temple was completed in 1604. It was rebuilt multiple times after attacks by Afghans and the British. The upper floors are covered in 750 kg of gold. The Langar serves free meals to over 100,000 people daily regardless of religion.', 31.6200, 74.8766, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Mahabodhi Temple', 'mahabodhi', 'Bihar', 'Bodh Gaya', 'Buddha', 'Buddhist', 'A UNESCO World Heritage Site marking the spot where Siddhartha Gautama attained enlightenment under the Bodhi tree. The temple is one of the four holiest sites in Buddhism.', 'The current temple dates from the 5th-6th century CE, built on the site of a temple commissioned by Emperor Ashoka in the 3rd century BCE. The Bodhi tree is a descendant of the original under which Buddha meditated. The temple was restored by Sir Alexander Cunningham and the Burmese in the 19th century.', 24.6951, 84.9914, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Kashi Vishwanath Temple', 'kashi-vishwanath', 'Uttar Pradesh', 'Varanasi', 'Shiva', 'North Indian', 'One of the twelve Jyotirlingas and the most sacred Shiva temple in India, located on the banks of the Ganges in Varanasi. The temple has a gold-plated spire and dome.', 'The original temple has been destroyed and rebuilt multiple times over centuries. The current structure was built by Maharani Ahilyabai Holkar in 1780, with the gold dome added by Maharaja Ranjit Singh in 1835. The temple is part of the Mandir-Masjid complex and is surrounded by narrow lanes of the old city.', 25.3109, 83.0106, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Vaishno Devi Temple', 'vaishno-devi', 'Jammu and Kashmir', 'Katra', 'Durga (Vaishno Devi)', 'Cave Shrine', 'A cave shrine dedicated to the goddess Vaishno Devi, located in the Trikuta Mountains. The shrine is a natural cave with three pindis representing the goddess in three forms.', 'The shrine is believed to be over 700 years old. Pilgrims trek 12 km from Katra to the cave at 1,580 m elevation. The cave narrows to just 1 ft at one point, requiring pilgrims to crawl. Over 10 million pilgrims visit annually, making it one of the most visited religious sites in India.', 33.0270, 74.9440, 300, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Siddhivinayak Temple', 'siddhivinayak', 'Maharashtra', 'Mumbai', 'Ganesha', 'Maharashtrian', 'One of the richest and most visited Ganesha temples in India, located in Prabhadevi, Mumbai. The idol has a unique trunk curving to the right.', 'The temple was built in 1801 by Laxman Vithu Patil. The wooden idol was later replaced with a stone one. The temple became widely popular in the 1970s-80s and now attracts celebrities, politicians, and millions of devotees. It is considered a siddha (wish-fulfilling) temple.', 19.0170, 72.8299, 60, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Shree Padmanabhaswamy Temple', 'padmanabhaswamy', 'Kerala', 'Thiruvananthapuram', 'Vishnu (Padmanabha)', 'Dravidian-Chera', 'A magnificent temple in Kerala dedicated to Vishnu reclining on Anantha, the cosmic serpent. The temple is famous for its hidden vaults containing enormous treasures.', 'The temple is mentioned in the Puranas and was rebuilt in the 18th century by the Travancore royal family. In 2011, the discovery of treasures worth an estimated $22 billion in the temple''s underground vaults made global headlines. The temple has a strict dress code and non-Hindus are not permitted.', 8.4833, 76.9367, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Lingaraja Temple', 'lingaraja', 'Odisha', 'Bhubaneswar', 'Shiva (Harihara)', 'Kalinga', 'The largest temple in Bhubaneswar, representing the finest example of Kalinga architecture. The temple complex covers 2.5 hectares and the main tower rises 55 m.', 'Built in the 11th century by King Jajati Keshari of the Somavamsi dynasty. The temple uniquely represents both Shiva and Vishnu (as Harihara). Over 500 smaller shrines surround the main temple. Non-Hindus can view the interior from a raised platform outside.', 20.2384, 85.8332, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Sri Ranganathaswamy Temple', 'srirangam', 'Tamil Nadu', 'Srirangam', 'Vishnu (Ranganatha)', 'Dravidian', 'The largest functioning Hindu temple in the world, covering 63 hectares with 7 concentric enclosures. The temple has 21 gopurams, with the tallest at 73 m.', 'The temple dates back to the 1st century CE, with most structures built between the 6th and 17th centuries by various Tamil dynasties. The temple was briefly damaged by Malik Kafur''s invasion in 1311. The temple complex is a small town with markets, residences, and 50 shrines.', 10.8626, 78.6896, 180, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Virupaksha Temple', 'virupaksha-hampi', 'Karnataka', 'Hampi', 'Shiva (Virupaksha)', 'Vijayanagara', 'The oldest and most prominent temple in the UNESCO World Heritage Site of Hampi. The temple features a 50 m tall gopuram and intricate pillars.', 'The temple has been in continuous use since the 7th century, predating the Vijayanagara Empire. It was patronized heavily during the Vijayanagara period (14th-16th centuries). The temple''s inverted shadow on a wall inside acts as a pinhole camera, projecting the gopuram image.', 15.3350, 76.4600, 120, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Shirdi Sai Baba Temple', 'shirdi-sai', 'Maharashtra', 'Shirdi', 'Sai Baba', 'Modern', 'The most visited Sai Baba shrine in the world, located in the small town of Shirdi. The temple complex includes the Samadhi Mandir, Dwarkamai, and Chavadi.', 'Sai Baba lived in Shirdi from 1858 until his death in 1918. The temple was built over his samadhi. The foundation stone was laid in 1919 and the temple was completed in 1922. The marble statue was installed in 1954. The temple attracts devotees from all religions.', 19.7666, 74.4764, 90, true, NOW(), NOW())
ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, state=EXCLUDED.state, city=EXCLUDED.city, deity=EXCLUDED.deity, arch_style=EXCLUDED.arch_style, description=EXCLUDED.description, history=EXCLUDED.history, latitude=EXCLUDED.latitude, longitude=EXCLUDED.longitude, visit_duration=EXCLUDED.visit_duration, updated_at=NOW(); INSERT INTO temples (name, slug, state, city, deity, arch_style, description, history, latitude, longitude, visit_duration, is_published, created_at, updated_at)
VALUES ('Sri Chennakeshava Temple', 'chennakeshava-belur', 'Karnataka', 'Belur', 'Vishnu (Chennakeshava)', 'Hoysala', 'The finest example of Hoysala architecture, built with soapstone and covered in intricate sculptures. The temple was built to commemorate the victory of Vishnuvardhana over the Cholas.', 'Built in 1117 CE by King Vishnuvardhana of the Hoysala Empire. The temple took 103 years to complete. The lathe-turned pillars and the madanikas (celestial dancers) on the walls are world-famous for their detail. The temple is a proposed UNESCO World Heritage Site.', 13.1631, 75.8614, 120, true, NOW(), NOW())
